// Systemkategorien und Prioritäten (später aus DB laden)
const categories = [
  'billing', 'technical_issue', 'account_access',
  'general_inquiry', 'complaint', 'cancellation',
  'product_feedback', 'legal', 'security', 'other'
];

const priorities = ['low', 'medium', 'high', 'urgent'];

const ticket = $input.first().json;

const systemPrompt = `Du bist ein Support-Klassifikationsdienst. Gib ausschließlich valides JSON gemäß Schema zurück.
Nutze nur die vorgegebenen Kategorien und Prioritäten. Wenn unsicher, setze confidence niedrig.

Kategorien: ${categories.join(', ')}
Prioritäten: ${priorities.join(', ')}`;

const userPrompt = `Ticket:
Betreff: ${ticket.subject}
Nachricht: ${ticket.body}
Absender: ${ticket.from_email}

Schema:
{
  "language": "de|en|...",
  "category": "string aus Kategorieliste",
  "priority": "low|medium|high|urgent",
  "sentiment": "neutral|positive|frustrated|angry|critical",
  "urgency": "low|normal|high|critical",
  "needs_customer_clarification": false,
  "is_automatable": false,
  "escalation_required": false,
  "reasoning_short": "max 2 Sätze",
  "confidence": 0.0
}`;

return [{ json: { systemPrompt, userPrompt, zammad_ticket_id: ticket.zammad_ticket_id } }];

// JSON validieren und parsen
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content;

let classification;
try {
  classification = JSON.parse(content);
} catch(e) {
  throw new Error(`KI-Ausgabe ist kein valides JSON: ${content}`);
}

// Schema validieren
const required = ['language','category','priority','sentiment','escalation_required','confidence'];
for (const field of required) {
  if (classification[field] === undefined) {
    throw new Error(`Pflichtfeld fehlt in KI-Ausgabe: ${field}`);
  }
}

const zammadTicketId = $('Build Classification Prompt').first().json.zammad_ticket_id;

return [{ json: { ...classification, zammad_ticket_id: zammadTicketId, prompt_version: 'v1.0' } }];

